import React, { useState, useEffect, useRef, useMemo } from 'react';
import { MapPin, Plus, Trash2, X, Download, ChevronDown, FileUp, FileDown, PlusCircle, Globe, Settings, Edit3, LogOut, Mail, Lock, User } from 'lucide-react';
import { initializeApp } from 'firebase/app';
import { getDatabase, ref, onValue, push, set, remove, update } from 'firebase/database';
import { getAuth, createUserWithEmailAndPassword, signInWithEmailAndPassword, onAuthStateChanged, signOut, updateProfile } from 'firebase/auth';
import * as htmlToImage from 'html-to-image';
import * as XLSX from 'xlsx';

// --- FIREBASE CONFIG ---
const firebaseConfig = {
  apiKey: "AIzaSyCDbnnEkMGYu3HMJAb8kViLnJZfazJ1qms",
  authDomain: "rp2026-b5d0a11111.firebaseapp.com",
  databaseURL: "https://rp2026-b5d0a11111-default-rtdb.asia-southeast1.firebasedatabase.app",
  projectId: "rp2026-b5d0a11111",
  storageBucket: "rp2026-b5d0a11111.firebasestorage.app",
  messagingSenderId: "864135040245",
  appId: "1:864135040245:web:3e8e2d336ce379575d49bc"
};

const app = initializeApp(firebaseConfig);
const db = getDatabase(app);
const auth = getAuth(app);

const translations = {
  zh: {
    title: "巡展规划助手", login: "登录", signup: "注册账号", email: "电子邮箱", password: "密码", username: "昵称",
    noAccount: "没有账号？点击注册", hasAccount: "已有账号？点击登录", logout: "退出登录", selectProject: "切换规划图",
    newProject: "新建规划图", renameProject: "重命名项目", importExcel: "导入 Excel", exportExcel: "导出 Excel",
    exportImage: "导出图片", addStop: "新增站点", settings: "设置", save: "保存", empty: "暂无数据", city: "城市", venue: "场馆"
  },
  en: {
    title: "Route Planner", login: "Login", signup: "Sign Up", email: "Email", password: "Password", username: "Username",
    noAccount: "No account? Sign up", hasAccount: "Have an account? Login", logout: "Logout", selectProject: "Switch Project",
    newProject: "New Project", renameProject: "Rename Project", importExcel: "Import Excel", exportExcel: "Export Excel",
    exportImage: "Export Image", addStop: "Add Stop", settings: "Settings", save: "Save", empty: "No Data", city: "City", venue: "Venue"
  }
};

const initialStopState = { name: '', venue: '', phase: '1', color: '#3b82f6', startDate: new Date().toISOString().split('T')[0] };

function App() {
  const [user, setUser] = useState(null);
  const [lang, setLang] = useState('zh');
  const t = translations[lang];
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [error, setError] = useState('');
  const [currentProjectId, setCurrentProjectId] = useState(null);
  const [projectList, setProjectList] = useState([]);
  const [stops, setStops] = useState([]);
  const [projectMetadata, setProjectMetadata] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [newStop, setNewStop] = useState(initialStopState);
  
  const mapRef = useRef(null);
  const clusterGroupRef = useRef(null);
  const mapContainerRef = useRef(null);
  const exportRef = useRef(null);
  const fileInputRef = useRef(null);

  const groupedStops = useMemo(() => {
    const groups = {};
    const sorted = [...stops].sort((a, b) => a.order - b.order);
    sorted.forEach(stop => {
      if (!groups[stop.phase]) groups[stop.phase] = { stops: [], color: stop.color };
      groups[stop.phase].stops.push(stop);
    });
    return groups;
  }, [stops]);

  // --- Auth & Initial Project Load ---
  useEffect(() => {
    return onAuthStateChanged(auth, (u) => {
      setUser(u);
      if (u) {
        onValue(ref(db, 'projects'), (snapshot) => {
          const data = snapshot.val() || {};
          const accessible = Object.entries(data)
            .filter(([id, meta]) => meta.ownerId === u.uid || (meta.collaborators && meta.collaborators[u.uid]))
            .map(([id, meta]) => ({ id, ...meta }));
          setProjectList(accessible);
          if (!currentProjectId && accessible.length > 0) setCurrentProjectId(accessible[0].id);
        });
      }
    });
  }, [currentProjectId]);

  // --- Sync Current Project Data ---
  useEffect(() => {
    if (!currentProjectId) return;
    return onValue(ref(db, `projects/${currentProjectId}`), (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setProjectMetadata(data);
        setStops(Object.entries(data.stops || {}).map(([id, val]) => ({ id, ...val })).sort((a,b) => a.order - b.order));
      }
    });
  }, [currentProjectId]);

  const canEdit = useMemo(() => {
    if (!user || !projectMetadata) return false;
    return projectMetadata.ownerId === user.uid || (projectMetadata.collaborators && projectMetadata.collaborators[user.uid] === 'editor');
  }, [user, projectMetadata]);

  // --- Map and Marker Rendering ---
  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current || !window.L) return;
    mapRef.current = window.L.map(mapContainerRef.current, { zoomControl: false }).setView([34.3416, 108.9398], 4);
    window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapRef.current);
    clusterGroupRef.current = window.L.markerClusterGroup().addTo(mapRef.current);
  }, []);

  useEffect(() => {
    if (!mapRef.current || !clusterGroupRef.current) return;
    clusterGroupRef.current.clearLayers();
    
    Object.values(groupedStops).forEach((group) => {
      group.stops.forEach(stop => {
        if (!stop.lat || !stop.lng) return;
        const icon = window.L.divIcon({
            html: `<div style="display:flex; align-items:center;"><svg width="32" height="32" viewBox="0 0 24 24" fill="${stop.color}" stroke="white" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg></div>`,
            iconSize: [32, 32], iconAnchor: [16, 32]
        });
        clusterGroupRef.current.addLayer(window.L.marker([stop.lat, stop.lng], { icon, phaseColor: stop.color }));
      });
    });
  }, [groupedStops]);

  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      if (isSignUp) {
        const res = await createUserWithEmailAndPassword(auth, email, password);
        await updateProfile(res.user, { displayName });
      } else {
        await signInWithEmailAndPassword(auth, email, password);
      }
    } catch (err) { setError(t.authError); }
  };

  if (!user) return (
    <div className="h-screen flex items-center justify-center bg-slate-50 font-sans">
        <div className="bg-white p-10 rounded-[40px] shadow-2xl w-full max-w-md">
            <h1 className="text-2xl font-black text-center mb-8 uppercase text-slate-800">{t.title}</h1>
            <form onSubmit={handleAuth} className="space-y-4">
                {isSignUp && <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none border-2 border-transparent focus:border-blue-500" placeholder={t.username} required value={displayName} onChange={e=>setDisplayName(e.target.value)} />}
                <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none border-2 border-transparent focus:border-blue-500" placeholder={t.email} type="email" required value={email} onChange={e=>setEmail(e.target.value)} />
                <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none border-2 border-transparent focus:border-blue-500" placeholder={t.password} type="password" required value={password} onChange={e=>setPassword(e.target.value)} />
                <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase hover:bg-slate-800 transition-all">{isSignUp ? t.signup : t.login}</button>
            </form>
            <button onClick={()=>setIsSignUp(!isSignUp)} className="w-full mt-6 text-xs font-bold text-slate-400 text-center">{isSignUp ? t.hasAccount : t.noAccount}</button>
        </div>
    </div>
  );

  return (
    <div ref={exportRef} className="flex flex-col h-screen bg-slate-50 overflow-hidden font-sans">
      <header className="flex items-center justify-between px-10 py-5 bg-white border-b z-10 shadow-sm">
        <div className="flex items-center gap-6">
          <h1 className="text-xl font-black text-blue-600">RP.2026</h1>
          <select className="bg-slate-50 font-bold text-sm rounded-xl px-4 py-2 outline-none border-none cursor-pointer" value={currentProjectId || ''} onChange={(e)=>setCurrentProjectId(e.target.value)}>
            {projectList.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
          <button onClick={()=>{const n=window.prompt(t.newProject); if(n){const nr=push(ref(db,'projects')); set(nr,{name:n,ownerId:user.uid,created:Date.now()}); setCurrentProjectId(nr.key);}}} className="text-blue-600 hover:scale-110 transition-transform"><PlusCircle size={24}/></button>
        </div>
        <div className="flex items-center gap-4">
          <Globe size={18} className="text-slate-400" />
          <select className="text-xs font-black outline-none bg-transparent cursor-pointer" value={lang} onChange={(e)=>setLang(e.target.value)}><option value="zh">ZH</option><option value="en">EN</option></select>
          <div className="h-8 w-[1px] bg-slate-100 mx-2" />
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-black">{(user.displayName||user.email).charAt(0).toUpperCase()}</div>
            <button onClick={()=>signOut(auth)} className="text-slate-400 hover:text-red-500 transition-colors"><LogOut size={20}/></button>
          </div>
          {canEdit && <button onClick={()=>setIsEditing(true)} className="px-6 py-3 bg-blue-600 text-white rounded-2xl font-black text-sm shadow-lg shadow-blue-100">+ {t.addStop}</button>}
        </div>
      </header>

      <main className="flex flex-1 p-6 gap-6 overflow-hidden">
        <div className="w-[380px] bg-white rounded-[40px] shadow-2xl border flex flex-col overflow-hidden relative border-slate-100">
            {isEditing ? (
              <div className="p-10 space-y-6 flex flex-col h-full animate-in slide-in-from-right-8 duration-300">
                <div className="flex justify-between items-center mb-4"><h2 className="text-2xl font-black text-blue-600">{t.addStop}</h2><button onClick={()=>setIsEditing(false)} className="p-2 bg-slate-50 rounded-full"><X size={20}/></button></div>
                <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none" placeholder={t.city} value={newStop.name} onChange={e=>setNewStop({...newStop,name:e.target.value})} />
                <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none" placeholder={t.venue} value={newStop.venue} onChange={e=>setNewStop({...newStop,venue:e.target.value})} />
                <div className="grid grid-cols-2 gap-4">
                    <select className="p-4 bg-slate-50 rounded-2xl font-bold outline-none" value={newStop.phase} onChange={e=>setNewStop({...newStop,phase:e.target.value})}>{[...Array(10)].map((_,i)=><option key={i+1} value={i+1}>Phase {i+1}</option>)}</select>
                    <input type="color" className="w-full h-14 p-1 bg-slate-50 rounded-2xl cursor-pointer" value={newStop.color} onChange={e=>setNewStop({...newStop,color:e.target.value})} />
                </div>
                <button onClick={async()=>{
                    const r=await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(newStop.name+' '+newStop.venue)}`);
                    const g=await r.json();
                    if(g[0]){ await set(push(ref(db,`projects/${currentProjectId}/stops`)),{...newStop,lat:parseFloat(g[0].lat),lng:parseFloat(g[0].lng),order:stops.length}); setIsEditing(false); setNewStop(initialStopState); }
                    else { alert("Location not found"); }
                }} className="mt-auto w-full py-5 bg-blue-600 text-white rounded-[24px] font-black shadow-lg uppercase">{t.save}</button>
              </div>
            ) : (
              <div className="flex-1 overflow-y-auto p-8 space-y-8">
                {stops.length === 0 && <div className="h-full flex flex-col items-center justify-center opacity-20 gap-4 mt-20"><MapPin size={64} /><p className="font-black">{t.empty}</p></div>}
                {Object.entries(groupedStops).map(([phase, data]) => (
                  <div key={phase} className="space-y-4">
                    <div className="px-4 py-1.5 rounded-full inline-block font-black text-[10px] uppercase tracking-widest" style={{ backgroundColor: `${data.color}15`, color: data.color }}>PHASE {phase}</div>
                    <div className="space-y-3">{data.stops.map(s => (
                      <div key={s.id} className="p-5 bg-white rounded-3xl border border-slate-50 flex items-center justify-between group hover:shadow-xl transition-all"><div className="flex items-center gap-4 overflow-hidden"><div className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ backgroundColor: s.color }} /><div className="truncate"><p className="font-black text-slate-700 text-sm truncate uppercase">{s.name}</p><p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{s.venue} · {s.startDate}</p></div></div>{canEdit && <button onClick={()=>remove(ref(db,`projects/${currentProjectId}/stops/${s.id}`))} className="opacity-0 group-hover:opacity-100 text-red-400 hover:bg-red-50 p-2 rounded-xl transition-all"><Trash2 size={16}/></button>}</div>
                    ))}</div>
                  </div>
                ))}
              </div>
            )}
        </div>
        <div className="flex-1 bg-white rounded-[56px] shadow-2xl border-[12px] border-white overflow-hidden relative">
            <div ref={mapContainerRef} style={{ height: '100%', width: '100%' }} className="z-0" />
            {!canEdit && stops.length > 0 && <div className="absolute top-8 left-8 z-[1000] bg-white/90 backdrop-blur px-5 py-2.5 rounded-2xl shadow-sm border border-slate-100 text-[10px] font-black uppercase text-slate-500">📍 Read Only Mode</div>}
        </div>
      </main>
    </div>
  );
}

export default App;